// Extract user message from webhook
const userMessage = $input.first().json.body.chatInput;
const sessionId = $input.first().json.headers['x-session-id'] || Date.now().toString();

return [{
  json: {
    userMessage: userMessage,
    sessionId: sessionId,
    timestamp: new Date().toISOString(),
    negotiationState: $input.first().json.body.negotiationState || 'none'
  }
}];

// Extract intent and clean response
const aiResponse = $input.first().json.message?.content || $input.first().json.text;
const intent = detectIntent(aiResponse);
const cleanedResponse = cleanOutput(aiResponse);

function detectIntent(text) {
  if (text.includes('ORDER_CONFIRMED')) return 'order';
  if (text.includes('CANCELLED')) return 'cancel';
  if (text.includes('BOOKING_CONFIRMED') || text.includes('SESSION_CONFIRMED')) return 'booking';
  if (text.includes('PRICE_NEGOTIATION')) return 'negotiation';
  return 'general';
}

function cleanOutput(text) {
  // Remove markdown and extra whitespace
  return text
    .replace(/[*_#`]/g, '')
    .replace(/\s+/g, ' ')
    .replace(/ORDER_CONFIRMED:|CANCELLED:|SESSION_CONFIRMED:/g, '')
    .trim();
}

return [{
  json: {
    ...$input.first().json,
    intent: intent,
    cleanedResponse: cleanedResponse,
    rawResponse: aiResponse
  }
}];
